-- Seefar Loyalty Platform - Supabase DDL
-- Generated for React Native Expo app with PostgreSQL backend

-- Enable UUID extension
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Users table
CREATE TABLE IF NOT EXISTS public.users (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "phoneNumber" text,
  email text UNIQUE NOT NULL,
  name text,
  avatar text,
  "totalPoints" integer DEFAULT 0,
  "currentTier" text DEFAULT 'bronze',
  "createdAt" timestamptz DEFAULT now(),
  "favoriteItems" text[] DEFAULT '{}',
  updated_at timestamptz DEFAULT now()
);

ALTER TABLE public.users ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view their own profile" ON public.users
  FOR SELECT USING (auth.uid() = id);

CREATE POLICY "Users can update their own profile" ON public.users
  FOR UPDATE USING (auth.uid() = id);

CREATE INDEX IF NOT EXISTS idx_users_email ON public.users(email);
CREATE INDEX IF NOT EXISTS idx_users_created_at ON public.users("createdAt");

-- Transactions table
CREATE TABLE IF NOT EXISTS public.transactions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  amount numeric NOT NULL,
  "pointsEarned" integer DEFAULT 0,
  date timestamptz DEFAULT now(),
  status text DEFAULT 'completed',
  "storeName" text,
  "storeAddress" text,
  "receiptNumber" text,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.transactions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view their own transactions" ON public.transactions
  FOR SELECT USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_transactions_user_id ON public.transactions("userId");
CREATE INDEX IF NOT EXISTS idx_transactions_date ON public.transactions(date);

-- Purchased items table
CREATE TABLE IF NOT EXISTS public.purchased_items (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "transactionId" uuid NOT NULL REFERENCES public.transactions(id) ON DELETE CASCADE,
  name text NOT NULL,
  quantity integer DEFAULT 1,
  price numeric NOT NULL,
  image text,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.purchased_items ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view purchased items from their transactions" ON public.purchased_items
  FOR SELECT USING (
    "transactionId" IN (
      SELECT id FROM public.transactions WHERE "userId" = auth.uid()
    )
  );

CREATE INDEX IF NOT EXISTS idx_purchased_items_transaction_id ON public.purchased_items("transactionId");

-- Rewards table
CREATE TABLE IF NOT EXISTS public.rewards (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  name text NOT NULL,
  description text,
  "pointsRequired" integer NOT NULL,
  category text,
  image text,
  "expiresAt" timestamptz,
  quantity integer DEFAULT 0,
  terms text[] DEFAULT '{}',
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.rewards ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can view rewards" ON public.rewards
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_rewards_category ON public.rewards(category);
CREATE INDEX IF NOT EXISTS idx_rewards_expires_at ON public.rewards("expiresAt");

-- Redemptions table
CREATE TABLE IF NOT EXISTS public.redemptions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  "rewardId" uuid NOT NULL REFERENCES public.rewards(id) ON DELETE CASCADE,
  "redeemedAt" timestamptz DEFAULT now(),
  "expiresAt" timestamptz,
  status text DEFAULT 'active',
  "confirmationCode" text UNIQUE,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.redemptions ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view their own redemptions" ON public.redemptions
  FOR SELECT USING (auth.uid() = "userId");

CREATE POLICY "Users can create redemptions" ON public.redemptions
  FOR INSERT WITH CHECK (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_redemptions_user_id ON public.redemptions("userId");
CREATE INDEX IF NOT EXISTS idx_redemptions_reward_id ON public.redemptions("rewardId");
CREATE INDEX IF NOT EXISTS idx_redemptions_status ON public.redemptions(status);

-- Payment methods table
CREATE TABLE IF NOT EXISTS public.payment_methods (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  "cardLast4" text,
  type text,
  "isDefault" boolean DEFAULT false,
  "expiryMonth" integer,
  "expiryYear" integer,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.payment_methods ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view their own payment methods" ON public.payment_methods
  FOR SELECT USING (auth.uid() = "userId");

CREATE POLICY "Users can manage their own payment methods" ON public.payment_methods
  FOR INSERT WITH CHECK (auth.uid() = "userId");

CREATE POLICY "Users can update their own payment methods" ON public.payment_methods
  FOR UPDATE USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_payment_methods_user_id ON public.payment_methods("userId");

-- Offers table
CREATE TABLE IF NOT EXISTS public.offers (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  title text NOT NULL,
  description text,
  image text,
  discount integer,
  "validUntil" timestamptz,
  code text UNIQUE,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.offers ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can view offers" ON public.offers
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_offers_valid_until ON public.offers("validUntil");

-- Notifications table
CREATE TABLE IF NOT EXISTS public.notifications (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  title text NOT NULL,
  message text,
  type text,
  read boolean DEFAULT false,
  "createdAt" timestamptz DEFAULT now()
);

ALTER TABLE public.notifications ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Anyone can view notifications" ON public.notifications
  FOR SELECT USING (true);

CREATE INDEX IF NOT EXISTS idx_notifications_created_at ON public.notifications("createdAt");

-- Orders table
CREATE TABLE IF NOT EXISTS public.orders (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "userId" uuid NOT NULL REFERENCES public.users(id) ON DELETE CASCADE,
  "orderNumber" text UNIQUE NOT NULL,
  subtotal numeric NOT NULL,
  tax numeric DEFAULT 0,
  discount numeric DEFAULT 0,
  total numeric NOT NULL,
  status text DEFAULT 'pending',
  "createdAt" timestamptz DEFAULT now(),
  "storeName" text,
  "storeAddress" text,
  "estimatedReadyTime" timestamptz,
  updated_at timestamptz DEFAULT now()
);

ALTER TABLE public.orders ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view their own orders" ON public.orders
  FOR SELECT USING (auth.uid() = "userId");

CREATE POLICY "Users can update their own orders" ON public.orders
  FOR UPDATE USING (auth.uid() = "userId");

CREATE INDEX IF NOT EXISTS idx_orders_user_id ON public.orders("userId");
CREATE INDEX IF NOT EXISTS idx_orders_status ON public.orders(status);
CREATE INDEX IF NOT EXISTS idx_orders_created_at ON public.orders("createdAt");

-- Order items table
CREATE TABLE IF NOT EXISTS public.order_items (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "orderId" uuid NOT NULL REFERENCES public.orders(id) ON DELETE CASCADE,
  name text NOT NULL,
  quantity integer DEFAULT 1,
  price numeric NOT NULL,
  image text,
  customizations text[] DEFAULT '{}',
  created_at timestamptz DEFAULT now()
);

ALTER TABLE public.order_items ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users can view order items from their orders" ON public.order_items
  FOR SELECT USING (
    "orderId" IN (
      SELECT id FROM public.orders WHERE "userId" = auth.uid()
    )
  );

CREATE INDEX IF NOT EXISTS idx_order_items_order_id ON public.order_items("orderId");

-- Auth trigger function for new user creation
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  INSERT INTO public.users (id, email, "phoneNumber", name, avatar, "totalPoints", "currentTier", "createdAt", "favoriteItems", updated_at)
  VALUES (
    NEW.id,
    NEW.email,
    NEW.raw_user_meta_data ->> 'phoneNumber',
    NEW.raw_user_meta_data ->> 'name',
    NEW.raw_user_meta_data ->> 'avatar',
    COALESCE((NEW.raw_user_meta_data ->> 'totalPoints')::integer, 0),
    COALESCE(NEW.raw_user_meta_data ->> 'currentTier', 'bronze'),
    now(),
    COALESCE((NEW.raw_user_meta_data ->> 'favoriteItems')::text[], '{}'),
    now()
  )
  ON CONFLICT (id) DO NOTHING;
  RETURN NEW;
END; $$;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created AFTER INSERT ON auth.users FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();
